///
/// `RSDP_PHYS` adresinden ACPI tablolarını ayrıştırır ve APIC bilgisini çıkarır.
/// Başarılıysa `true`, başarısızsa `false` döner.
pub fn init() -> bool {
    let rsdp = RSDP_PHYS.load(Ordering::SeqCst);
    if rsdp == 0 {
        return false;
    }

    let handler = HhdmAcpiHandler;
